/// <summary>
/// this class will handle voyage editor for sales order lines and transfer order shipments
/// </summary>
public final class ETGITMTableFormOutbound
{
    private ITMTable itmTable;
    private SalesTable salesTable;
    private ITMId newShipId;

}

Method.Source:
public boolean create(boolean _foredit = false)
{
    FormOpenMode FormOpenMode;
    Args        args = new Args();
    FormRun     shipTableCreate;

    args.parmEnum(_foredit ? FormOpenMode::ForEdit : FormOpenMode::ForNew);
    args.parmEnumType(enumNum(FormOpenMode));
    args.name(this.createForm());
    args.caller(this);

    shipTableCreate = classfactory.formRunClass(args);
    shipTableCreate.init();
    shipTableCreate.run();
    shipTableCreate.wait();

    return shipTableCreate.closedOk();
}

public boolean shipmentEditor()
{
    Args        args = new Args();
    FormRun     editorForm;

    args.parmEnum(FormOpenMode::ForEdit);
    args.parmEnumType(enumNum(FormOpenMode));
    args.name(this.editorFormName());
    args.caller(this);

    editorForm = classfactory.formRunClass(args);
    editorForm.init();
    editorForm.run();
    editorForm.wait();

    return editorForm.closedOk();
}

public ITMId parmNewShipId(ITMId _newShipId = newShipId)
{
    newShipId = _newShipId;
    return newShipId;
}

public ITMTable parmITMTable(ITMTable _itmTable = itmTable)
{
    itmTable = _itmTable;
    return itmTable;
}

public SalesTable parmSalesTable(SalesTable _salesTable = salesTable)
{
    salesTable = _salesTable;
    return salesTable;
}

public static ETGITMTableFormOutbound construct()
{
    return new ETGITMTableFormOutbound();
}
